# S-plane coordinate mapping
SP_X_MIN, SP_X_MAX = -20, 5
SP_Y_MIN, SP_Y_MAX = -20, 20

def s_to_screen(sx, sy, rect):
    px = rect.x + int((sx - SP_X_MIN) / (SP_X_MAX - SP_X_MIN) * rect.width)
    py = rect.y + rect.height - int((sy - SP_Y_MIN) / (SP_Y_MAX - SP_Y_MIN) * rect.height)
    return px, py

def screen_to_s(px, py, rect):
    sx = SP_X_MIN + (px - rect.x) / rect.width * (SP_X_MAX - SP_X_MIN)
    sy = SP_Y_MIN + (rect.y + rect.height - py) / rect.height * (SP_Y_MAX - SP_Y_MIN)
    return sx, sy

def draw_splane(surface, p1, p2, rect, dragging_pole):
    """Draw the S-plane with movable poles"""
    pygame.draw.rect(surface, DARK_GRAY, rect)
    pygame.draw.rect(surface, GRAY, rect, 1)

    title = font_large.render("S-Plane (drag poles with mouse)", True, WHITE)
    surface.blit(title, (rect.x + 10, rect.y + 5))

    # Grid
    for sx in range(int(SP_X_MIN), int(SP_X_MAX) + 1, 5):
        x, _ = s_to_screen(sx, 0, rect)
        pygame.draw.line(surface, (50, 50, 50), (x, rect.y), (x, rect.y + rect.height), 1)
        lbl = font_small.render(str(sx), True, GRAY)
        surface.blit(lbl, (x - 8, rect.y + rect.height // 2 + 2))

    for sy in range(int(SP_Y_MIN), int(SP_Y_MAX) + 1, 5):
        _, y = s_to_screen(0, sy, rect)
        pygame.draw.line(surface, (50, 50, 50), (rect.x, y), (rect.x + rect.width, y), 1)
        if sy != 0:
            lbl = font_small.render(str(sy), True, GRAY)
            surface.blit(lbl, (rect.x + rect.width // 2 + 2, y - 6))

    # Axes
    ox, oy = s_to_screen(0, 0, rect)
    pygame.draw.line(surface, LIGHT_GRAY, (rect.x, oy), (rect.x + rect.width, oy), 2)
    pygame.draw.line(surface, LIGHT_GRAY, (ox, rect.y), (ox, rect.y + rect.height), 2)

    # Axis labels
    lbl = font_small.render("Re(s)", True, LIGHT_GRAY)
    surface.blit(lbl, (rect.x + rect.width - 40, oy + 5))
    lbl = font_small.render("Im(s)", True, LIGHT_GRAY)
    surface.blit(lbl, (ox + 5, rect.y + 5))

    # Draw unit circle in frequency (|Im| = wn)
    b, c = get_coeffs(p1, p2)
    if c > 0:
        wn = math.sqrt(c)
        # Draw circle of radius wn centered at origin
        cx_s, cy_s = s_to_screen(0, 0, rect)
        r_px = int(wn / (SP_Y_MAX - SP_Y_MIN) * rect.height)
        pygame.draw.circle(surface, (60, 60, 80), (cx_s, cy_s), r_px, 1)
        lbl = font_small.render(f"wn={wn:.2f}", True, (80, 80, 120))
        surface.blit(lbl, (cx_s + r_px + 2, cy_s - 10))

    # Draw lines from origin to poles
    px1, py1 = s_to_screen(p1.real, p1.imag, rect)
    px2, py2 = s_to_screen(p2.real, p2.imag, rect)
    pygame.draw.line(surface, (80, 80, 80), (ox, oy), (px1, py1), 1)
    pygame.draw.line(surface, (80, 80, 80), (ox, oy), (px2, py2), 1)

    # Draw poles as X marks
    pole_color1 = YELLOW if dragging_pole == 1 else RED
    pole_color2 = YELLOW if dragging_pole == 2 else RED
    size = 8
    pygame.draw.line(surface, pole_color1, (px1 - size, py1 - size), (px1 + size, py1 + size), 3)
    pygame.draw.line(surface, pole_color1, (px1 + size, py1 - size), (px1 - size, py1 + size), 3)
    pygame.draw.line(surface, pole_color2, (px2 - size, py2 - size), (px2 + size, py2 + size), 3)
    pygame.draw.line(surface, pole_color2, (px2 + size, py2 - size), (px2 - size, py2 + size), 3)

    # Labels
    lbl = font_small.render(f"p1={p1.real:.2f}+{p1.imag:.2f}j", True, pole_color1)
    surface.blit(lbl, (px1 + 10, py1 - 10))
    lbl = font_small.render(f"p2={p2.real:.2f}{p2.imag:.2f}j", True, pole_color2)
    surface.blit(lbl, (px2 + 10, py2 + 2))

    # Stability indicator
    stable = p1.real < 0 and p2.real < 0
    stab_color = GREEN if stable else RED
    stab_text = "STABLE (LHP)" if stable else "UNSTABLE (RHP)"
    lbl = font_med.render(stab_text, True, stab_color)
    surface.blit(lbl, (rect.x + 10, rect.y + rect.height - 20))

