def draw_info(surface, p1, p2, rect):
    pygame.draw.rect(surface, DARK_GRAY, rect)
    pygame.draw.rect(surface, GRAY, rect, 1)

    b, c = get_coeffs(p1, p2)
    b_real = b.real if hasattr(b, 'real') else b
    c_real = c.real if hasattr(c, 'real') else c

    lines = [
        ("Transfer Function", WHITE, font_title),
        ("", WHITE, font_small),
        ("G(s) = 100 / (s^2 + b*s + c)", CYAN, font_med),
        ("", WHITE, font_small),
        (f"b (damping coeff) = {b_real:.4f}", LIGHT_GRAY, font_med),
        (f"c (spring coeff)  = {c_real:.4f}", LIGHT_GRAY, font_med),
        ("", WHITE, font_small),
        ("Poles:", WHITE, font_med),
        (f"  p1 = {p1.real:.4f} + {p1.imag:.4f}j", RED, font_med),
        (f"  p2 = {p2.real:.4f} + {p2.imag:.4f}j", RED, font_med),
        ("", WHITE, font_small),
    ]

    if c_real > 0:
        wn = math.sqrt(abs(c_real))
        zeta = b_real / (2 * wn) if wn > 0 else 0
        wd = wn * math.sqrt(max(0, 1 - zeta**2))
        lines += [
            ("System Parameters:", WHITE, font_med),
            (f"  Natural freq wn = {wn:.4f} rad/s", YELLOW, font_med),
            (f"  Damping ratio z = {zeta:.4f}", YELLOW, font_med),
            (f"  Damped freq  wd = {wd:.4f} rad/s", YELLOW, font_med),
            ("", WHITE, font_small),
        ]
        if zeta < 1:
            lines.append(("  Underdamped system", GREEN, font_med))
        elif zeta == 1:
            lines.append(("  Critically damped", ORANGE, font_med))
        else:
            lines.append(("  Overdamped system", ORANGE, font_med))

    lines += [
        ("", WHITE, font_small),
        ("DC Gain (s=0):", WHITE, font_med),
        (f"  |G(0)| = {abs(G(0, p1, p2)):.4f}", CYAN, font_med),
        ("", WHITE, font_small),
        ("Controls:", WHITE, font_large),
        ("  Drag X marks to move poles", LIGHT_GRAY, font_small),
        ("  Poles stay conjugate", LIGHT_GRAY, font_small),
        ("  R = Reset to default", LIGHT_GRAY, font_small),
    ]

    y = rect.y + 8
    for text, color, fnt in lines:
        if text:
            lbl = fnt.render(text, True, color)
            surface.blit(lbl, (rect.x + 10, y))
        y += fnt.get_height() + 2
        if y > rect.y + rect.height - 10:
            break

# ─────────────────────────────────────────────
# Main loop
# ─────────────────────────────────────────────
def get_pole_screen_pos(p1, p2):
    px1, py1 = s_to_screen(p1.real, p1.imag, SPLANE_RECT)
    px2, py2 = s_to_screen(p2.real, p2.imag, SPLANE_RECT)
    return (px1, py1), (px2, py2)

dragging_pole = 0  # 0=none, 1=pole1, 2=pole2
DRAG_RADIUS = 15

clock = pygame.time.Clock()
needs_redraw = True

print("Starting G(s) Interactive Visualization...")
print("G(s) = 100 / (s^2 + 5s + 100)")
print("Default poles at s = -2.5 ± 9.682j")
print("Drag the X marks in the S-plane to move poles!")
print("Press R to reset poles to default.")

running = True
while running:
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            running = False
        elif event.type == pygame.KEYDOWN:
            if event.key == pygame.K_ESCAPE:
                running = False
            elif event.key == pygame.K_r:
                pole1 = complex(-2.5, 9.682)
                pole2 = complex(-2.5, -9.682)
                needs_redraw = True
                print("Poles reset to default: -2.5 ± 9.682j")

        elif event.type == pygame.MOUSEBUTTONDOWN:
            if event.button == 1:
                mx, my = event.pos
                (px1, py1), (px2, py2) = get_pole_screen_pos(pole1, pole2)
                if math.hypot(mx - px1, my - py1) < DRAG_RADIUS:
                    dragging_pole = 1
                elif math.hypot(mx - px2, my - py2) < DRAG_RADIUS:
                    dragging_pole = 2

        elif event.type == pygame.MOUSEBUTTONUP:
            if event.button == 1:
                dragging_pole = 0

        elif event.type == pygame.MOUSEMOTION:
            if dragging_pole in (1, 2):
                mx, my = event.pos
                if SPLANE_RECT.collidepoint(mx, my):
                    sx, sy = screen_to_s(mx, my, SPLANE_RECT)
                    # Keep conjugate symmetry: pole1 has positive imag, pole2 negative
                    if dragging_pole == 1:
                        pole1 = complex(sx, abs(sy))
                        pole2 = complex(sx, -abs(sy))
                    else:
                        pole2 = complex(sx, -abs(sy))
                        pole1 = complex(sx, abs(sy))
                    needs_redraw = True

    if needs_redraw:
        screen.fill(BLACK)

        # Draw title bar
        title_surf = font_title.render(
            "G(s) = 100/(s^2+5s+100) Visualization  |  Interactive S-Plane", True, WHITE)
        screen.blit(title_surf, (10, 5))

        draw_3d_surface(screen, pole1, pole2, SURF3D_RECT)
        draw_bode(screen, pole1, pole2, BODE_RECT)
        draw_splane(screen, pole1, pole2, SPLANE_RECT, dragging_pole)
        draw_info(screen, pole1, pole2, INFO_RECT)

        pygame.display.flip()
        needs_redraw = False

    clock.tick(60)

pygame.quit()
sys.exit()